        scale = parseFloat(scale) || 0;
        sourceA = this.#determineSource(sourceA);
        sourceB = this.#determineSource(sourceB);
        const channelR = this.displacementByChannel({
            channel: 'R',
            sourceA: sourceA,
            sourceB: sourceB,
            scale: error + scale,
            result: 'red_channel',
        });

        const channelG = this.displacementByChannel({
            channel: 'G',
            sourceA: sourceA,
            sourceB: sourceB,
            scale: error + (scale * 2),
            result: 'green_channel',
        });

        const channelB = this.displacementByChannel({
            channel: 'B',
            sourceA: sourceA,
            sourceB: sourceB,
            scale: error + (scale * 3),
            result: 'blue_channel',
        });

